function solve(words) {

   const n = words.length;

   if (n === 0) return [];

   if (n === 1) return [0];

   const m = n - 1;

   function getLCP(s1, s2) {

      let minLen = Math.min(s1.length, s2.length);

      for (let i = 0; i < minLen; i++) {

         if (s1[i] !== s2[i]) {

            return i;

         }

      }

      return minLen;

   }

   const lcp = new Array(m);

   for (let j = 0; j < m; j++) {

      lcp[j] = getLCP(words[j], words[j + 1]);

   }

   const prefix_max = new Array(m);

   prefix_max[0] = lcp[0];

   for (let i = 1; i < m; i++) {

      prefix_max[i] = Math.max(prefix_max[i - 1], lcp[i]);

   }

   const suffix_max = new Array(m);

   suffix_max[m - 1] = lcp[m - 1];

   for (let i = m - 2; i >= 0; i--) {

      suffix_max[i] = Math.max(suffix_max[i + 1], lcp[i]);

   }

   const answer = new Array(n);

   for (let i = 0; i < n; i++) {

      if (i === 0) {

         if (n === 1) {

            answer[i] = 0;

         } else if (n === 2) {

            answer[i] = 0;

         } else {

            // new array is words[1..n-1], which has length n-1 >= 2

            // the lcp is suffix_max[1]

            answer[i] = suffix_max[1];

         }

      } else if (i === n - 1) {

         if (n === 1) {

            answer[i] = 0;

         } else if (n === 2) {

            answer[i] = 0;

         } else {

            // new array is words[0..n-2], which has length n-1 >= 2

            // the lcp is prefix_max[n-3]

            answer[i] = prefix_max[n - 3];

         }

      } else {

         let left_part_max = 0;

         if (i - 2 >= 0) {

            left_part_max = prefix_max[i - 2];

         }

         let right_part_max = 0;

         if (i + 1 <= m - 1) {

            right_part_max = suffix_max[i + 1];

         }

         const new_pair = getLCP(words[i - 1], words[i + 1]);

         answer[i] = Math.max(left_part_max, right_part_max, new_pair);

      }

   }

   return answer;

}

